import React, { useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Webcam from 'react-webcam';
import axios from 'axios';

const CameraUpload = () => {
  const navigate = useNavigate();
  const webcamRef = useRef(null);
  const [capturedImage, setCapturedImage] = useState(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [cameraMode, setCameraMode] = useState('user');

  const capturePhoto = () => {
    const imageSrc = webcamRef.current.getScreenshot();
    setCapturedImage(imageSrc);
  };

  const retakePhoto = () => {
    setCapturedImage(null);
  };

  const detectAndSolve = async () => {
    setIsProcessing(true);
    try {
      const response = await axios.post('http://localhost:8000/api/detect/', {
        image: capturedImage
      });
      
      if (response.data.success) {
        const solveResponse = await axios.post('http://localhost:8000/api/solve/', response.data.cubeState);
        if (solveResponse.data.success) {
          navigate('/solve', { 
            state: { 
              solution: solveResponse.data.solution, 
              cubeState: response.data.cubeState 
            } 
          });
        } else {
          alert(solveResponse.data.error);
        }
      } else {
        alert(response.data.error);
      }
    } catch (error) {
      alert('Failed to detect cube. Please try again.');
    } finally {
      setIsProcessing(false);
    }
  };

  const switchCamera = () => {
    setCameraMode(prev => prev === 'user' ? 'environment' : 'user');
  };

  return (
    <div className="camera-upload">
      <button className="back-btn" onClick={() => navigate('/input')}>← Back</button>
      <h2>Scan Your Cube</h2>
      
      {!capturedImage ? (
        <>
          <div className="webcam-container">
            <Webcam
              audio={false}
              ref={webcamRef}
              screenshotFormat="image/jpeg"
              videoConstraints={{ facingMode: cameraMode }}
              className="webcam"
            />
          </div>
          <div className="camera-controls">
            <button className="switch-btn" onClick={switchCamera}>Switch Camera</button>
            <button className="capture-btn" onClick={capturePhoto}>Capture Photo</button>
          </div>
        </>
      ) : (
        <>
          <div className="preview-container">
            <img src={capturedImage} alt="Captured" className="preview" />
          </div>
          <div className="action-buttons">
            <button className="retake-btn" onClick={retakePhoto}>Retake</button>
            <button className="solve-btn" onClick={detectAndSolve} disabled={isProcessing}>
              {isProcessing ? 'Processing...' : 'Solve Cube'}
            </button>
          </div>
        </>
      )}
    </div>
  );
};

export default CameraUpload;
